return (async () => {
  const reviewDirectory = inputs.review_directory;
  if (typeof reviewDirectory !== 'string' || !reviewDirectory.trim()) throw new Error('review_directory must be a non-empty absolute path.');
  if (typeof process.getBuiltinModule !== 'function') throw new Error('This script requires a Node.js runtime with process.getBuiltinModule.');
  const { realpath, stat } = process.getBuiltinModule('node:fs/promises');
  const path = process.getBuiltinModule('node:path');
  const { spawn } = process.getBuiltinModule('node:child_process');
  if (!path.isAbsolute(reviewDirectory)) throw new Error('review_directory must be an absolute path.');
  const resolvedDirectory = await realpath(reviewDirectory);
  if (!(await stat(resolvedDirectory)).isDirectory()) throw new Error('review_directory must reference a directory.');
  const runGit = (args) => new Promise((resolve, reject) => {
    const child = spawn('git', args, { shell: false, windowsHide: true });
    let stdout = '';
    let stderr = '';
    let size = 0;
    const timer = setTimeout(() => { child.kill(); reject(new Error('Git scope collection timed out.')); }, 15000);
    child.stdout.on('data', (chunk) => { size += chunk.length; if (size > 4 * 1024 * 1024) { child.kill(); reject(new Error('Git scope output exceeded 4 MiB.')); return; } stdout += String(chunk); });
    child.stderr.on('data', (chunk) => { stderr += String(chunk); });
    child.on('error', (error) => { clearTimeout(timer); reject(error); });
    child.on('close', (code) => { clearTimeout(timer); if (code === 0) resolve(stdout); else reject(new Error(stderr.trim() || `Git exited with code ${code}.`)); });
  });
  const repositoryRoot = (await runGit(['-C', resolvedDirectory, 'rev-parse', '--show-toplevel'])).trim();
  const relativeScope = path.relative(repositoryRoot, resolvedDirectory);
  if (relativeScope.startsWith('..') || path.isAbsolute(relativeScope)) throw new Error('review_directory must stay inside its Git repository.');
  const pathspec = relativeScope ? relativeScope.split(path.sep).join('/') : '.';
  const readPaths = async (args) => (await runGit(['-C', repositoryRoot, ...args, '--', pathspec])).split('\0').filter(Boolean);
  const [stagedFiles, unstagedFiles, untrackedFiles] = await Promise.all([
    readPaths(['diff', '--cached', '--name-only', '-z']),
    readPaths(['diff', '--name-only', '-z']),
    readPaths(['ls-files', '--others', '--exclude-standard', '-z']),
  ]);
  const changedFiles = [...new Set([...stagedFiles, ...unstagedFiles, ...untrackedFiles])].sort();
  return { review_directory: resolvedDirectory, repository_root: repositoryRoot, staged_files: stagedFiles.sort(), unstaged_files: unstagedFiles.sort(), untracked_files: untrackedFiles.sort(), changed_files: changedFiles };
})();
